import{_ as o,a as r,b as i,c as n,d as a,e as s,f as p}from"./chunks/dvr.p8O1ibuT.js";import{_ as l}from"./chunks/multiconf.KueTB99t.js";import{c as g,Q as c,j as h,g as d,n as e,m as x}from"./chunks/framework.rlpw0eGz.js";const v=JSON.parse('{"title":"VRX Setup Guide","description":"Step-by-step guide for setting up the VRX Runcam WifiLink — connection, WebUI, channels, DVR and RSSI monitoring.","frontmatter":{"title":"VRX Setup Guide","description":"Step-by-step guide for setting up the VRX Runcam WifiLink — connection, WebUI, channels, DVR and RSSI monitoring.","head":[["link",{"rel":"canonical","href":"https://openfpv.com.ua/en/getting-started/groundstation"}],["link",{"rel":"alternate","hreflang":"uk","href":"https://openfpv.com.ua/getting-started/groundstation"}],["link",{"rel":"alternate","hreflang":"en","href":"https://openfpv.com.ua/en/getting-started/groundstation"}],["link",{"rel":"alternate","hreflang":"x-default","href":"https://openfpv.com.ua/getting-started/groundstation"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:url","content":"https://openfpv.com.ua/en/getting-started/groundstation"}],["meta",{"property":"og:title","content":"VRX Setup Guide"}],["meta",{"property":"og:description","content":"Step-by-step guide for setting up the VRX Runcam WifiLink — connection, WebUI, channels, DVR and RSSI monitoring."}],["meta",{"property":"og:image","content":"https://openfpv.com.ua/og-started.png"}],["meta",{"property":"og:locale","content":"en_US"}],["meta",{"property":"og:locale:alternate","content":"uk_UA"}],["meta",{"name":"twitter:image","content":"https://openfpv.com.ua/og-started.png"}],["meta",{"name":"twitter:title","content":"VRX Setup Guide"}],["meta",{"name":"twitter:description","content":"Step-by-step guide for setting up the VRX Runcam WifiLink — connection, WebUI, channels, DVR and RSSI monitoring."}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@graph\\":[{\\"@type\\":\\"Organization\\",\\"@id\\":\\"https://openfpv.com.ua/#org\\",\\"name\\":\\"OpenFPV Ukraine\\",\\"url\\":\\"https://openfpv.com.ua\\",\\"logo\\":\\"https://openfpv.com.ua/logo-light.png\\",\\"sameAs\\":[\\"https://github.com/Maxwell456/openipc-docs-ukr\\"]},{\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Home\\",\\"item\\":\\"https://openfpv.com.ua/en/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Getting Started\\",\\"item\\":\\"https://openfpv.com.ua/en/getting-started/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"VRX Setup Guide\\"}]},{\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"VRX Setup Guide\\",\\"description\\":\\"Step-by-step guide for setting up the VRX Runcam WifiLink — connection, WebUI, channels, DVR and RSSI monitoring.\\",\\"inLanguage\\":\\"en-US\\",\\"url\\":\\"https://openfpv.com.ua/en/getting-started/groundstation\\",\\"image\\":\\"https://openfpv.com.ua/og-started.png\\",\\"dateModified\\":\\"2026-05-31T11:48:56.000Z\\",\\"author\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"},\\"publisher\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"}}]}"]]},"headers":[],"relativePath":"en/getting-started/groundstation.md","filePath":"en/getting-started/groundstation.md","lastUpdated":1780228136000}'),u={name:"en/getting-started/groundstation.md"};function m(b,t,y,f,S,w){return c(),h("div",null,[...t[0]||(t[0]=[d("h1",{id:"vrx-setup-guide",tabindex:"-1"},[e("VRX Setup Guide "),d("a",{class:"header-anchor",href:"#vrx-setup-guide","aria-label":'Permalink to "VRX Setup Guide"'},"​")],-1),d("h2",{id:"runcam-wifilink-receiver",tabindex:"-1"},[e("Runcam WifiLink Receiver "),d("a",{class:"header-anchor",href:"#runcam-wifilink-receiver","aria-label":'Permalink to "Runcam WifiLink Receiver"'},"​")],-1),d("div",{style:{"text-align":"center"}},[d("iframe",{width:"560",height:"315",src:"https://www.youtube.com/embed/BP7Ns7H9wvI?si=sUkZiTPDYfQbjkLS",title:"YouTube video player",frameborder:"0",allow:"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share",referrerpolicy:"strict-origin-when-cross-origin",allowfullscreen:""})],-1),x('<div class="warning custom-block"><p class="custom-block-title">Warning</p><p>Do not connect power to the VRX if the HDMI cable is connected but the HDMI source is off — this may damage the HDMI output!</p></div><ol><li>Connect <strong>DC 9–30V</strong> power and a <strong>miniHDMI-to-HDMI</strong> cable to your goggles or monitor.</li><li>Using the <strong>HID joystick</strong> you can change the communication channel (default <code>161 → 5.8 GHz</code>).</li><li>Power on the drone and the VRX. By default both are set to channel <code>161</code> and resolution <code>1920×1080</code> — video will appear within <strong>10 seconds</strong>.</li></ol><br><p>💡 <em><strong>That&#39;s it! You can now fly on OpenIPC digital video.</strong></em></p><hr><h2 id="additional-vrx-settings" tabindex="-1">Additional VRX Settings <a class="header-anchor" href="#additional-vrx-settings" aria-label="Permalink to &quot;Additional VRX Settings&quot;">​</a></h2><h3 id="_1-accessing-the-webui" tabindex="-1">1. Accessing the WebUI <a class="header-anchor" href="#_1-accessing-the-webui" aria-label="Permalink to &quot;1. Accessing the WebUI&quot;">​</a></h3><p>To change the VRX resolution (FullHD or HD), enter <strong>AP Mode (Wi-Fi access point)</strong>: hold the joystick on the VRX until the screen shows <strong>&quot;AP mode ON&quot;</strong>.</p><p>📶 A Wi-Fi network will appear: <code>RadxaGroundStation</code> 🔑 Password: <code>radxaopenipc</code></p><p>After connecting, open your browser and go to:</p><p><a href="http://radxa-zero3.local/" target="_blank" rel="noreferrer">http://radxa-zero3.local/</a></p><blockquote><p>In the WebUI you can: • change communication channels • download or view DVR recordings • configure Adaptive Link • select resolution • view the RSSI graph</p></blockquote><hr><h3 id="_2-main-webui-features" tabindex="-1">2. Main WebUI Features <a class="header-anchor" href="#_2-main-webui-features" aria-label="Permalink to &quot;2. Main WebUI Features&quot;">​</a></h3><img src="'+o+'" alt="homegs" width="1000px"><ul><li><strong>DVR</strong></li><li><strong>VRX Settings</strong></li><li><strong>Camera Settings</strong></li><li><strong>RSSI Graph</strong> <em>(works when VRX and Air Unit are connected)</em></li></ul><hr><h3 id="_3-configuring-resolution" tabindex="-1">3. Configuring Resolution <a class="header-anchor" href="#_3-configuring-resolution" aria-label="Permalink to &quot;3. Configuring Resolution&quot;">​</a></h3><p>Go to <strong>Groundstation Editor → Screen-mode → Edit</strong>. Set the resolution, e.g. <code>1280×720</code> — it must <strong>match the Air Unit settings</strong>.</p><img src="'+r+'" alt="gs-edit" width="1000px"><hr><h3 id="_4-configuring-the-communication-channel" tabindex="-1">4. Configuring the Communication Channel <a class="header-anchor" href="#_4-configuring-the-communication-channel" aria-label="Permalink to &quot;4. Configuring the Communication Channel&quot;">​</a></h3><p>Go to <strong>Groundstation Editor → wifibroadcast.cfg → Edit</strong>. Set a different channel (e.g. <code>140</code>, <code>64</code>, etc.) — <strong>it must match the channel on the Air Unit</strong>.</p><img src="'+i+'" alt="gs-channel" width="1000px"><h4 id="📡-5-8-ghz-channel-table-20-mhz" tabindex="-1">📡 5.8 GHz Channel Table (20 MHz) <a class="header-anchor" href="#📡-5-8-ghz-channel-table-20-mhz" aria-label="Permalink to &quot;📡 5.8 GHz Channel Table (20 MHz)&quot;">​</a></h4><table style="width:100%;border-collapse:collapse;margin:15px 0;"><thead><tr><th style="padding:10px;border:1px solid #ddd;text-align:left;">Channel</th><th style="padding:10px;border:1px solid #ddd;text-align:left;">Frequency (MHz)</th><th style="padding:10px;border:1px solid #ddd;text-align:left;">Note</th></tr></thead><tbody><tr><td style="padding:8px;border:1px solid #ddd;">36</td><td style="padding:8px;border:1px solid #ddd;">5180</td><td style="padding:8px;border:1px solid #ddd;">Wi-Fi</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">40</td><td style="padding:8px;border:1px solid #ddd;">5200</td><td style="padding:8px;border:1px solid #ddd;">Wi-Fi</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">44</td><td style="padding:8px;border:1px solid #ddd;">5220</td><td style="padding:8px;border:1px solid #ddd;">Wi-Fi</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">48</td><td style="padding:8px;border:1px solid #ddd;">5240</td><td style="padding:8px;border:1px solid #ddd;">Wi-Fi</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">52</td><td style="padding:8px;border:1px solid #ddd;">5260</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">56</td><td style="padding:8px;border:1px solid #ddd;">5280</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">60</td><td style="padding:8px;border:1px solid #ddd;">5300</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">64</td><td style="padding:8px;border:1px solid #ddd;">5320</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">100</td><td style="padding:8px;border:1px solid #ddd;">5500</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">104</td><td style="padding:8px;border:1px solid #ddd;">5520</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">108</td><td style="padding:8px;border:1px solid #ddd;">5540</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">112</td><td style="padding:8px;border:1px solid #ddd;">5560</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">116</td><td style="padding:8px;border:1px solid #ddd;">5580</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">120</td><td style="padding:8px;border:1px solid #ddd;">5600</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">124</td><td style="padding:8px;border:1px solid #ddd;">5620</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">128</td><td style="padding:8px;border:1px solid #ddd;">5640</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">132</td><td style="padding:8px;border:1px solid #ddd;">5660</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">136</td><td style="padding:8px;border:1px solid #ddd;">5680</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">140</td><td style="padding:8px;border:1px solid #ddd;">5700</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">144</td><td style="padding:8px;border:1px solid #ddd;">5720</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">149</td><td style="padding:8px;border:1px solid #ddd;">5745</td><td style="padding:8px;border:1px solid #ddd;">No DFS (usually allowed)</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">153</td><td style="padding:8px;border:1px solid #ddd;">5765</td><td style="padding:8px;border:1px solid #ddd;">No DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">157</td><td style="padding:8px;border:1px solid #ddd;">5785</td><td style="padding:8px;border:1px solid #ddd;">No DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">161</td><td style="padding:8px;border:1px solid #ddd;">5805</td><td style="padding:8px;border:1px solid #ddd;">Most popular</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">165</td><td style="padding:8px;border:1px solid #ddd;">5825</td><td style="padding:8px;border:1px solid #ddd;">No DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">169</td><td style="padding:8px;border:1px solid #ddd;">5845</td><td style="padding:8px;border:1px solid #ddd;"><em>Non-standard</em></td></tr><tr><td style="padding:8px;border:1px solid #ddd;">173</td><td style="padding:8px;border:1px solid #ddd;">5865</td><td style="padding:8px;border:1px solid #ddd;"><em>Non-standard</em></td></tr><tr><td style="padding:8px;border:1px solid #ddd;">177</td><td style="padding:8px;border:1px solid #ddd;">5885</td><td style="padding:8px;border:1px solid #ddd;"><em>Non-standard</em></td></tr></tbody></table><blockquote><p><strong>❗ What is DFS (Dynamic Frequency Selection):</strong> A technology that allows Wi-Fi or FPV devices to operate on frequencies that may overlap with military or meteorological radars. If radar activity is detected, the device automatically switches channels.</p></blockquote><hr><h3 id="_5-camera-settings-air-unit" tabindex="-1">5. Camera Settings (Air Unit) <a class="header-anchor" href="#_5-camera-settings-air-unit" aria-label="Permalink to &quot;5. Camera Settings (Air Unit)&quot;">​</a></h3><p>Go to: <strong>Camera Settings → Load Current Config</strong></p><ul><li>Wait for the settings to load from the camera</li><li>Make your changes</li><li>Save</li><li>Restart <strong>Majestic</strong></li></ul><img src="'+n+'" alt="gs-majestic" width="1000px"><img src="'+a+'" alt="gs-majestic1" width="1000px"><hr><h3 id="_6-rssi-graph" tabindex="-1">6. RSSI Graph <a class="header-anchor" href="#_6-rssi-graph" aria-label="Permalink to &quot;6. RSSI Graph&quot;">​</a></h3><p>The <strong>RSSI</strong> graph lets you monitor signal strength, link quality, and verify antenna placement and link stability in real time.</p><img src="'+s+'" alt="gs-rssi" width="1000px"><h3 id="_7-dvr" tabindex="-1">7. DVR <a class="header-anchor" href="#_7-dvr" aria-label="Permalink to &quot;7. DVR&quot;">​</a></h3><p>Download or delete your flight recordings.</p><img src="'+p+'" alt="dvr" width="1000px"><h3 id="_8-connecting-radxa-to-your-home-network" tabindex="-1">8. Connecting Radxa to Your Home Network <a class="header-anchor" href="#_8-connecting-radxa-to-your-home-network" aria-label="Permalink to &quot;8. Connecting Radxa to Your Home Network&quot;">​</a></h3><p><strong>Required software</strong></p><ol><li>Win32 Disk Imager</li><li>SD Memory Card Formatter</li><li>PuTTY (SSH)</li><li>WinSCP (FTP)</li></ol><p><strong>Initial Radxa Setup</strong></p><ol><li>Flash the Radxa image (v1.9.9) to a microSD card using Win32 Disk Imager.</li><li>Insert the card, connect a keyboard and monitor, disable Wi-Fi card power (⚠️ required).</li><li>Power on, log in via SSH (root/root).</li><li>Run <code>nmtui</code> → connect to your home Wi-Fi → reboot.</li><li>(Optional) AP mode → radxa-zero3.local → Web UI.</li></ol><p><img src="'+l+'" alt="multiconf" width="800px"><br></p><p><strong>Camera Setup (Runcam WiFiLink v1/v2)</strong></p><ol><li>Connect the Ethernet cable to your router or PC (IP 192.168.1.10).</li><li>Open OpenIPC Configurator → Connect → select your camera.</li><li><strong>Camera</strong>: Resolution (1920×1080 or 1280×720) → Bitrate (e.g. 12 228 kbps; with Alink — auto).</li><li><strong>Telemetry</strong>: enable UART0 + Mavlink → restart.</li><li><strong>Firmware</strong>: update firmware → Update.</li><li><strong>Advanced</strong>: enable Alink → view logs.</li></ol>',48)])])}const D=g(u,[["render",m]]);export{v as __pageData,D as default};
